class Solution {
    public int findNthDigit(int n) {
        long numDigits = 1;
        long start = 1;
        long count = 9;
        while (n > count * numDigits) {
            n -= count * numDigits;
            start *= 10;
            numDigits += 1;
            count *= 10;
        }
        start += (n - 1) / numDigits;
        return (int) (start + (n - 1) % numDigits) / numDigits % 10;
    }
}
```

